class BubbleSort {
private:
    vector<int> arr;
public:
    BubbleSort(vector<int> a) : arr(a) {}

    vector<int> sort() {
        int n = arr.size();
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n-i-1; j++) {
                if (arr[j] > arr[j+1]) {
                    swap(arr[j], arr[j+1]);
                }
            }
        }
        return arr;
    }
};

