struct BubbleSort {
    arr: Vec<i32>,
}

impl BubbleSort {
    fn new(arr: Vec<i32>) -> Self {
        BubbleSort { arr }
    }

    fn sort(&mut self) -> &Vec<i32> {
        let n = self.arr.len();
        for i in 0..n {
            for j in 0..n-i-1 {
                if self.arr[j] > self.arr[j+1] {
                    self.arr.swap(j, j+1);
                }
            }
        }
        &self.arr
    }
}

